        for (auto& [id, p] : players) {
            if (id == new_id) continue;
            if (p.team == 0) team0_count++;
            else team1_count++;
        }
        player.team = (team0_count <= team1_count) ? 0 : 1;

        player.respawn();

        // Send connect acknowledgment
        ConnectAckPacket ack;
        memset(&ack, 0, sizeof(ack));
        ack.header.type = PacketType::CONNECT_ACK;
        ack.header.player_id = 0;
        ack.header.sequence = sequence_counter++;
        ack.header.timestamp = get_timestamp();
        ack.assigned_id = new_id;
