        memset(&spawn, 0, sizeof(spawn));
        spawn.header.type = PacketType::PLAYER_SPAWN;
        spawn.header.player_id = 0;
        spawn.header.sequence = sequence_counter++;
        spawn.header.timestamp = get_timestamp();
        spawn.spawned_player_id = new_id;
